SELECT COUNT(data_object_id) AS total_data_objects
FROM data_objects
WHERE spacecraft_id = 1;

SELECT m.mission_name
FROM missions m
WHERE m.actual_cost > (SELECT AVG(budget) FROM missions);

SELECT spacecraft_id, COUNT(data_object_id) AS total_data_objects
FROM data_objects
GROUP BY spacecraft_id;

SELECT mission_name, budget AS total_budget
FROM missions
ORDER BY budget DESC;

SELECT mission_name
FROM missions
WHERE budget = (SELECT MAX(budget) FROM missions);
